// Miri is an interpreter that detects undefined behavior.
// Install: rustup +nightly component add miri
// Run:     cargo +nightly miri test
// Run:     cargo +nightly miri run

// Miri catches:
// - Out-of-bounds memory access
// - Use of dangling pointers
// - Use of uninitialized memory
// - Violation of aliasing rules (Stacked Borrows)
// - Data races
// - Memory leaks
// - Invalid enum/bool values

// Example test that Miri would catch:
#[test]
fn test_no_ub() {
    let mut v = vec![1, 2, 3];
    let ptr = v.as_ptr();

    unsafe {
        // Safe: reading within bounds
        assert_eq!(*ptr, 1);
        assert_eq!(*ptr.add(1), 2);
        assert_eq!(*ptr.add(2), 3);

        // Miri would catch: *ptr.add(3) -- out of bounds!
    }
}

// Instead of raw pointers, use safe abstractions:

// 1. Use MaybeUninit for uninitialized memory
use std::mem::MaybeUninit;

fn safe_uninit() -> [i32; 5] {
    let mut arr: [MaybeUninit<i32>; 5] = unsafe {
        MaybeUninit::uninit().assume_init()
    };

    for (i, elem) in arr.iter_mut().enumerate() {
        elem.write(i as i32 * 10);
    }

    // SAFETY: All elements have been initialized above
    unsafe {
        std::mem::transmute::<[MaybeUninit<i32>; 5], [i32; 5]>(arr)
    }
}

// 2. Use NonNull instead of raw *mut T
use std::ptr::NonNull;

struct SafeBox<T> {
    ptr: NonNull<T>,  // Guaranteed non-null
}

impl<T> SafeBox<T> {
    fn new(value: T) -> Self {
        let boxed = Box::new(value);
        let ptr = NonNull::from(Box::leak(boxed));
        SafeBox { ptr }
    }

    fn get(&self) -> &T {
        unsafe { self.ptr.as_ref() }
    }
}

impl<T> Drop for SafeBox<T> {
    fn drop(&mut self) {
        unsafe {
            let _ = Box::from_raw(self.ptr.as_ptr());
        }
    }
}

fn main() {
    let arr = safe_uninit();
    println!("{:?}", arr);  // [0, 10, 20, 30, 40]

    let sb = SafeBox::new("Hello".to_string());
    println!("{}", sb.get());
}
